<?php
declare(strict_types=1);
namespace Database\Seeders;
use App\Factory\Models\FactoryBlueprint; use App\Factory\Models\FactoryCapability; use App\Factory\Models\FactoryExecution; use App\Factory\Models\FactoryExecutionLog; use App\Factory\Models\FactoryProject; use Illuminate\Database\Seeder; use Illuminate\Support\Str;
class FactoryCoreSeeder extends Seeder { public function run(): void { if (class_exists('Spatie\\Permission\\Models\\Permission')) { foreach(config('factory.permissions',[]) as $permission){ \Spatie\Permission\Models\Permission::findOrCreate($permission); } } $project=FactoryProject::firstOrCreate(['slug'=>'vitrine-ai-pro-master'],['uuid'=>(string)Str::uuid(),'name'=>config('factory.project_name','Vitrine AI Pro Master'),'code'=>'VITRINE_AI_PRO_MASTER','description'=>'Projeto principal integrado ao Factory Core v1.0.','status'=>'active']); $cap=FactoryCapability::firstOrCreate(['factory_project_id'=>$project->id,'slug'=>'content-generation'],['uuid'=>(string)Str::uuid(),'name'=>'Content Generation','code'=>'CONTENT_GENERATION','description'=>'Capability padrão.','type'=>'ai','status'=>'active']); $bp=FactoryBlueprint::firstOrCreate(['factory_project_id'=>$project->id,'slug'=>'default-content-blueprint'],['uuid'=>(string)Str::uuid(),'factory_capability_id'=>$cap->id,'name'=>'Default Content Blueprint','code'=>'DEFAULT_CONTENT_BLUEPRINT','status'=>'active','version'=>1]); $exec=FactoryExecution::firstOrCreate(['name'=>'Execução inicial Factory Core','factory_project_id'=>$project->id],['uuid'=>(string)Str::uuid(),'factory_capability_id'=>$cap->id,'factory_blueprint_id'=>$bp->id,'status'=>'pending','attempt'=>1]); FactoryExecutionLog::firstOrCreate(['factory_execution_id'=>$exec->id,'event'=>'seed_created'],['uuid'=>(string)Str::uuid(),'level'=>'info','message'=>'Registro inicial criado pelo FactoryCoreSeeder.']); } }
